// HMAC-SHA256 validation of the inbound webhook (R-02: fail-closed). Mirrors health-check.json:20.
const crypto = require('crypto');
const secret = $env['CREATE_ADR_WEBHOOK_SECRET'] ?? '';
if (!secret) throw new Error('CREATE_ADR_WEBHOOK_SECRET missing — fail-closed (R-02)');
const sig = $input.first().headers['x-signature-256'] ?? '';
const rawBody = $input.first().binary?.data?.data
  ? Buffer.from($input.first().binary.data.data, 'base64').toString('utf8')
  : JSON.stringify($input.first().json);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
if (!sig || sig.length !== expected.length || !crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) {
  throw new Error('Invalid HMAC — dropping payload (R-02)');
}

const body = $input.first().json ?? {};
const title = body.title;
const context = body.context;
if (!title || typeof title !== 'string') throw new Error('Missing or non-string title');
if (!context || typeof context !== 'string') throw new Error('Missing or non-string context');
const chat_id = body.chat_id ? String(body.chat_id) : '';

return [{
  json: {
    intent: 'adr architecture decision record document ' + title,
    chat_id,
    user_id: String(body.user_id ?? ''),
    timestamp: new Date().toISOString(),
    metadata: { title, context }
  }
}];

// HMAC-SHA256 over the exact body string the Router will read (ADR-0003). Mirrors health-check.json:41.
const crypto = require('crypto');
const p = $input.first().json;
const bodyObj = {
  intent: p.intent,
  chat_id: p.chat_id,
  user_id: p.user_id,
  timestamp: p.timestamp,
  metadata: p.metadata,
};
const bodyStr = JSON.stringify(bodyObj);
const secret = $env['SKILLS_ROUTER_SECRET'] ?? '';
if (!secret) throw new Error('SKILLS_ROUTER_SECRET missing — fail-closed (R-02)');
const sig = 'sha256=' + crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
return [{ json: { _bodyStr: bodyStr, _sig: sig, _chat_id: p.chat_id, _meta: p.metadata } }];

// Short-lived JWT — GitHub caps App JWTs at 10 min; iat-60s tolerates clock skew.
const crypto = require('crypto');
const appId = $env['GITHUB_APP_ID'] ?? '';
const pem = $env['GITHUB_APP_PRIVATE_KEY'] ?? '';
if (!appId) throw new Error('GITHUB_APP_ID missing — fail-closed');
if (!pem) throw new Error('GITHUB_APP_PRIVATE_KEY missing — fail-closed');
const now = Math.floor(Date.now() / 1000);
const header = { alg: 'RS256', typ: 'JWT' };
const payload = { iat: now - 60, exp: now + 540, iss: appId };
const b64u = (obj) => Buffer.from(JSON.stringify(obj)).toString('base64url');
const signingInput = b64u(header) + '.' + b64u(payload);
const signer = crypto.createSign('RSA-SHA256');
signer.update(signingInput);
const sig = signer.sign(pem).toString('base64url');
return [{ json: { _jwt: signingInput + '.' + sig } }];

// Numbering: max(NNNN-) + 1, zero-padded to 4 (excludes template.md by regex).
// Slug: lowercase, [a-z0-9-]+, capped at 60 to keep branch refs under git's 255-char limit.
// Template substitution: plain String.replace on the four MADR placeholders — no markdown parsing.
const listing = $('List ADRs').first().json;
if (!Array.isArray(listing)) throw new Error('List ADRs response is not an array — fail-closed');
const nums = listing
  .map((e) => (e?.name ?? '').match(/^(\d{4})-/))
  .filter(Boolean)
  .map((m) => parseInt(m[1], 10));
const nextNum = (nums.length ? Math.max(...nums) : 0) + 1;
const nnnn = String(nextNum).padStart(4, '0');

const meta = $('Compute Skills Router HMAC').first().json._meta;
const title = meta.title;
const context = meta.context;
const slug = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 60);
if (!slug) throw new Error('Title slug is empty after sanitization — fail-closed');

const tplResp = $('Read Template').first().json;
if (!tplResp?.content) throw new Error('Template content missing — fail-closed');
const tpl = Buffer.from(tplResp.content, 'base64').toString('utf8');
const today = new Date().toISOString().slice(0, 10);
const rendered = tpl
  .replace('# ADR-NNNN: [Title]', '# ADR-' + nnnn + ': ' + title)
  .replace('**Date:** YYYY-MM-DD', '**Date:** ' + today)
  .replace(/\*\*Status:\*\* \[Proposed[^\]]*\]/, '**Status:** Proposed')
  .replace(/\[Describe the architectural context[^\]]*\]/, context);

const path = 'docs/adr/' + nnnn + '-' + slug + '.md';
const branch = 'claude/adr-' + nnnn + '-' + slug;
const contentB64 = Buffer.from(rendered, 'utf8').toString('base64');

return [{ json: { _nnnn: nnnn, _slug: slug, _title: title, _context: context, _path: path, _branch: branch, _contentB64: contentB64 } }];

const pr = $input.first().json;
const plan = $('Build ADR + Branch Plan').first().json;
const chat_id = $('Compute Skills Router HMAC').first().json._chat_id;
const url = pr?.html_url ?? '(URL missing in API response)';
return [{ json: { chat_id, text: 'ADR-' + plan._nnnn + ' "' + plan._title + '" PR opened: ' + url } }];

const r = $input.first().json;
const chat_id = $('Compute Skills Router HMAC').first().json._chat_id;
let reason;
if (r?.status === 'pending_approval') {
  reason = 'pending_approval (' + (r.reason ?? 'requires_approval') + ')';
} else if (r?.matched === false) {
  reason = 'no skill matched';
} else if (r?.skill && r.skill !== 'create-adr') {
  reason = 'router routed to a different skill: ' + r.skill;
} else {
  reason = 'unexpected router response';
}
return [{ json: { chat_id, text: 'Create ADR not executed — ' + reason } }];
